namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }

    public string FullCode => $"{DepartmentCode} {CourseNumber}";
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD from MIT and has 15 years of experience teaching introductory programming. Her research focuses on CS education and pedagogy.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms).", Credits = 4, Schedule = "TTh 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park is an expert in algorithm design with publications in top conferences. He previously worked at Google Research.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "310", Title = "Database Systems", Description = "Relational database design, SQL, transaction processing, and introduction to NoSQL systems.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez specializes in distributed database systems and has contributed to several open-source database projects." },
        new() { Id = 4, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "405", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, and practical applications of ML in industry.", Credits = 3, Schedule = "TTh 2:00–3:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD from MIT and has 15 years of experience teaching introductory programming. Her research focuses on CS education and pedagogy." },
        new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor has taught calculus for over 20 years and authored two widely-used textbooks on the subject.", IsFeatured = true },
        new() { Id = 6, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications.", Credits = 3, Schedule = "TTh 9:00–10:15 AM", InstructorName = "Dr. Anita Gupta", InstructorBio = "Dr. Gupta's research spans algebraic geometry and mathematical physics. She is a recipient of the university's Distinguished Teaching Award." },
        new() { Id = 7, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor has taught calculus for over 20 years and authored two widely-used textbooks on the subject." },
        new() { Id = 8, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with laboratory component.", Credits = 4, Schedule = "MWF 10:00–10:50 AM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Alan Hoffman", InstructorBio = "Dr. Hoffman is an experimental physicist whose research focuses on condensed matter systems. He emphasizes hands-on learning." },
        new() { Id = 9, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Continuation of General Physics I.", Credits = 4, Schedule = "MWF 10:00–10:50 AM + Lab Tue 2:00–4:00 PM", InstructorName = "Dr. Alan Hoffman", InstructorBio = "Dr. Hoffman is an experimental physicist whose research focuses on condensed matter systems. He emphasizes hands-on learning.", IsFeatured = true },
        new() { Id = 10, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "101", Title = "Composition and Rhetoric", Description = "Development of academic writing skills, critical thinking, and argumentation strategies.", Credits = 3, Schedule = "TTh 11:00 AM–12:15 PM", InstructorName = "Prof. Linda Hayes", InstructorBio = "Prof. Hayes is a published author and writing coach with expertise in rhetoric and composition studies." },
        new() { Id = 11, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present day.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Michael Ross", InstructorBio = "Dr. Ross is a scholar of 20th-century American fiction and has published extensively on Faulkner and Morrison." },
        new() { Id = 12, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World History to 1500", Description = "Survey of major civilizations, cultures, and events from antiquity through the medieval period.", Credits = 3, Schedule = "TTh 1:00–2:15 PM", InstructorName = "Dr. Patricia Nguyen", InstructorBio = "Dr. Nguyen specializes in ancient Mediterranean history and archaeological methods." },
        new() { Id = 13, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "205", Title = "Modern European History", Description = "Political, social, and cultural developments in Europe from the Enlightenment to the present.", Credits = 3, Schedule = "MWF 3:00–3:50 PM", InstructorName = "Dr. David Klein", InstructorBio = "Dr. Klein is an expert in 19th-century European intellectual history and the history of science.", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.FullCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

