arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-5 fw-bold">Welcome to the Course Catalog</h1>
    <p class="lead text-muted">Browse departments, explore courses, and submit enrollment requests.</p>
    <a href="/courses" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
</div>

<section class="mb-5">
    <h2>Featured Courses</h2>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mt-2">
        @foreach (var course in _featured)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.FullCode — @course.Title</h5>
                        <p class="card-text text-muted">@course.Credits credits · @course.Schedule</p>
                        <p class="card-text">@Truncate(course.Description, 100)</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h2>Departments</h2>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mt-2">
        @foreach (var dept in _departments)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name (@dept.Code)</h5>
                        <p class="card-text">@dept.Description</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private List<Course> _featured = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featured = Catalog.GetFeaturedCourses();
        _departments = Catalog.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Courses</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="row g-3 mb-4 mt-2">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in _courses)
            {
                <tr>
                    <td>@course.FullCode</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> _courses = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@if (_course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <div class="alert alert-warning">Course not found.</div>
    <a href="/courses">← Back to Courses</a>
}
else
{
    <PageTitle>@_course.FullCode — @_course.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item active">@_course.FullCode</li>
        </ol>
    </nav>

    <h1>@_course.FullCode — @_course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@_course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p><strong>@_course.Schedule</strong></p>

            <h4 class="mt-4">Credits</h4>
            <p><span class="badge bg-primary fs-6">@_course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-header bg-dark text-white">
                    <h5 class="mb-0">Instructor</h5>
                </div>
                <div class="card-body">
                    <h6>@_course.InstructorName</h6>
                    <p class="text-muted">@_course.InstructorBio</p>
                </div>
            </div>

            <a href="/enroll?courseId=@_course.Id" class="btn btn-success w-100 mt-3">Enroll in This Course</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p class="text-muted">Fill out the form below to request enrollment in a course.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
            <strong>@_selectedCourseTitle</strong> has been received. You will be notified once it is processed.</p>
        <hr />
        <a href="/courses" class="btn btn-outline-primary">Browse More Courses</a>
    </div>
}
else
{
    <form method="post" class="mt-4" style="max-width: 600px;">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="_model.StudentName" value="@_model.StudentName"
                   class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="_model.StudentId" value="@_model.StudentId"
                   class="form-control" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="_model.CourseId" class="form-select" required>
                <option value="">— Select a course —</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id" selected="@(course.Id == _model.CourseId)">
                        @course.FullCode — @course.Title
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Request</button>
        <a href="/courses" class="btn btn-link">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest _model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (CourseId.HasValue && _model.CourseId == 0)
