@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p class="text-muted">Fill out the form below to request enrollment in a course.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
            <strong>@_selectedCourseTitle</strong> has been received. You will be notified once it is processed.</p>
        <hr />
        <a href="/courses" class="btn btn-outline-primary">Browse More Courses</a>
    </div>
}
else
{
    <form method="post" class="mt-4" style="max-width: 600px;">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="_model.StudentName" value="@_model.StudentName"
                   class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="_model.StudentId" value="@_model.StudentId"
                   class="form-control" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="_model.CourseId" class="form-select" required>
                <option value="">— Select a course —</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id" selected="@(course.Id == _model.CourseId)">
                        @course.FullCode — @course.Title
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Request</button>
        <a href="/courses" class="btn btn-link">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest _model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (CourseId.HasValue && _model.CourseId == 0)
            _model.CourseId = CourseId.Value;

        // Check if this is a POST (form was submitted)
        if (!string.IsNullOrEmpty(_model.StudentName) && !string.IsNullOrEmpty(_model.StudentId) && _model.CourseId > 0)
        {
            _selectedCourseTitle = Catalog.GetCourse(_model.CourseId)?.Title ?? "Unknown";
            _submitted = true;
        }
    }
}

